/* ── COMPOSANTS DE TABLEAUX ── */
function TableInscriptions({ data }) {
  return (
    <div style={{ background: C.white, borderRadius: "24px", padding: "32px", boxShadow: "0 4px 16px rgba(17,76,90,0.04)" }}>
      <h2 style={{ fontSize: "18px", fontWeight: 800, color: C.teal, marginBottom: "24px" }}>Dernières Inscriptions</h2>
      <table style={{ width: "100%", borderCollapse: "collapse" }}>
        <thead><tr style={{ borderBottom: `2px solid ${C.arctic}`, textAlign: "left" }}>
          <th style={{ padding: "16px", fontSize: "12px", color: C.gray }}>PARTICIPANT</th>
          <th style={{ padding: "16px", fontSize: "12px", color: C.gray }}>SÉJOUR</th>
          <th style={{ padding: "16px", fontSize: "12px", color: C.gray }}>MONTANT</th>
        </tr></thead>
        <tbody>
          {data?.map(b => (
            <tr key={b.id} style={{ borderBottom: `1px solid ${C.arctic}` }}>
              <td style={{ padding: "16px", fontSize: "13px", fontWeight: 700, color: C.teal }}>{b.client?.nom} {b.client?.prenom}</td>
              <td style={{ padding: "16px", fontSize: "13px" }}>{b.sejour?.titre}</td>
              <td style={{ padding: "16px", fontSize: "13px", fontWeight: 800 }}>{b.montantPaye} €</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

function TableSejours({ data }) {
  return (
    <div style={{ background: C.white, borderRadius: "24px", padding: "32px" }}>
      <table style={{ width: "100%", borderCollapse: "collapse" }}>
        <thead><tr style={{ borderBottom: `2px solid ${C.arctic}`, textAlign: "left" }}>
          <th style={{ padding: "16px", fontSize: "12px", color: C.gray }}>SÉJOUR</th>
          <th style={{ padding: "16px", fontSize: "12px", color: C.gray }}>SAISON</th>
          <th style={{ padding: "16px", fontSize: "12px", color: C.gray }}>PLACES</th>
          <th style={{ padding: "16px", fontSize: "12px", color: C.gray }}>PRIX</th>
        </tr></thead>
        <tbody>
          {data?.map(s => (
            <tr key={s.id} style={{ borderBottom: `1px solid ${C.arctic}` }}>
              <td style={{ padding: "16px", fontSize: "13px", fontWeight: 700 }}>{s.titre}</td>
              <td style={{ padding: "16px", fontSize: "13px" }}>{s.saison}</td>
              <td style={{ padding: "16px", fontSize: "13px" }}>{s.places}</td>
              <td style={{ padding: "16px", fontSize: "13px", fontWeight: 800 }}>{s.prix} €</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

/* ── MODALE SÉPARÉE POUR LA LISIBILITÉ ── */
function ModalCreerSejour({ setIsModalOpen, isSubmitting, setIsSubmitting }) {
  return (
    <div style={{ position: "absolute", inset: 0, zIndex: 9999, display: "flex", alignItems: "center", justifyContent: "center", background: "rgba(17, 76, 90, 0.4)", backdropFilter: "blur(4px)" }}>
      <div style={{ background: C.white, width: "100%", maxWidth: "650px", maxHeight: "90vh", overflowY: "auto", borderRadius: "24px", padding: "32px", position: "relative" }}>
        <button onClick={() => setIsModalOpen(false)} style={{ position: "absolute", top: "24px", right: "24px", background: C.arctic, border: "none", width: "32px", height: "32px", borderRadius: "50%", cursor: "pointer" }}><X size={16}/></button>
        <h2 style={{ fontSize: "20px", fontWeight: 900, color: C.teal, marginBottom: "24px" }}>Créer un nouveau séjour</h2>
        <form action={async (formData) => {
          setIsSubmitting(true);
          await creerSejour(formData);
          setIsSubmitting(false);
          setIsModalOpen(false);
        }} style={{ display: "flex", flexDirection: "column", gap: "20px" }}>
          <div style={{ display: "flex", gap: "16px" }}>
            <input type="text" name="titre" required placeholder="Titre" style={{ flex: 1, padding: "12px", borderRadius: "12px", border: `1px solid ${C.lightGray}` }} />
            <input type="text" name="lieu" required placeholder="Lieu" style={{ flex: 1, padding: "12px", borderRadius: "12px", border: `1px solid ${C.lightGray}` }} />
          </div>
          <div style={{ display: "flex", gap: "16px" }}>
            <input type="date" name="dateDebut" required style={{ flex: 1, padding: "12px", borderRadius: "12px", border: `1px solid ${C.lightGray}` }} />
            <input type="date" name="dateFin" required style={{ flex: 1, padding: "12px", borderRadius: "12px", border: `1px solid ${C.lightGray}` }} />
          </div>
          <div style={{ display: "flex", gap: "16px", zIndex: 20 }}>
            <CustomSelect name="saison" label="Saison" options={[{ value: "Automne", label: "Automne", icon: Tent, color: C.saffron },{ value: "Hiver", label: "Hiver", icon: Tent, color: C.teal },{ value: "Printemps", label: "Printemps", icon: Tent, color: "#10b981" },{ value: "Été", label: "Été", icon: Tent, color: C.yellow }]} />
            <CustomSelect name="statut" label="Statut" options={[{ value: "Brouillon", label: "Brouillon", icon: Clock, color: C.gray },{ value: "Publié", label: "Publié", icon: CheckCircle2, color: "#10b981" }]} />
          </div>
          <ImageUpload />
          <div style={{ display: "flex", justifyContent: "flex-end", gap: "12px" }}>
            <button type="button" onClick={() => setIsModalOpen(false)} style={{ cursor: "pointer", background: "none", border: "none", color: C.gray }}>Annuler</button>
            <button type="submit" disabled={isSubmitting} style={{ background: C.yellow, padding: "12px 24px", borderRadius: "12px", border: "none", fontWeight: 800 }}>{isSubmitting ? "En cours..." : "Enregistrer"}</button>
          </div>
        </form>
      </div>
    </div>
  );
}